import numpy as np
from scipy.optimize import minimize

class VQClassifier:
    def __init__(self, n_qubits: int, n_layers: int):
        self.n_qubits = n_qubits
        self.n_layers = n_layers
        self.dim = 2 ** n_qubits
        self.n_params = n_qubits * n_layers * 3

    def _apply_gate(self, state, gate, qubit):
        new_state = np.zeros_like(state)
        for i in range(len(state)):
            bit = (i >> qubit) & 1
            for new_bit in range(2):
                j = (i & ~(1 << qubit)) | (new_bit << qubit)
                new_state[j] += gate[new_bit, bit] * state[i]
        return new_state

    def _apply_cnot(self, state, ctrl, tgt):
        new_state = np.zeros_like(state)
        for i in range(len(state)):
            cb = (i >> ctrl) & 1
            if cb == 1:
                j = i ^ (1 << tgt)
                new_state[j] = state[i]
            else:
                new_state[i] = state[i]
        return new_state

    def _ry(self, theta):
        c, s = np.cos(theta/2), np.sin(theta/2)
        return np.array([[c, -s], [s, c]])

    def _rx(self, theta):
        c, s = np.cos(theta/2), np.sin(theta/2)
        return np.array([[c, -1j*s], [-1j*s, c]])

    def _rz(self, theta):
        return np.diag([np.exp(-1j*theta/2), np.exp(1j*theta/2)])

    def encode(self, x: np.ndarray) -> np.ndarray:
        state = np.zeros(self.dim, dtype=complex)
        state[0] = 1
        for i in range(min(self.n_qubits, len(x))):
            state = self._apply_gate(state, self._ry(np.pi * x[i]), i)
        return state

    def variational_circuit(self, state: np.ndarray, params: np.ndarray) -> np.ndarray:
        idx = 0
        for layer in range(self.n_layers):
            for q in range(self.n_qubits):
                state = self._apply_gate(state, self._rx(params[idx]), q)
                idx += 1
            for q in range(self.n_qubits):
                state = self._apply_gate(state, self._ry(params[idx]), q)
                idx += 1
            for q in range(self.n_qubits):
                state = self._apply_gate(state, self._rz(params[idx]), q)
                idx += 1
            for q in range(self.n_qubits - 1):
                state = self._apply_cnot(state, q, q + 1)
        return state

    def forward(self, x: np.ndarray, params: np.ndarray) -> float:
        state = self.encode(x)
        state = self.variational_circuit(state, params)
        prob_1 = sum(np.abs(state[i])**2 for i in range(self.dim) if (i & 1) == 1)
        return prob_1

    def loss(self, params: np.ndarray, X: np.ndarray, y: np.ndarray) -> float:
        eps = 1e-10
        total = 0
        for xi, yi in zip(X, y):
            p = np.clip(self.forward(xi, params), eps, 1 - eps)
            total += -yi * np.log(p) - (1 - yi) * np.log(1 - p)
        return total / len(X)

    def train(self, X: np.ndarray, y: np.ndarray, maxiter: int = 100) -> dict:
        init = np.random.randn(self.n_params) * 0.1
        history = []

        def callback(p):
            l = self.loss(p, X, y)
            history.append(l)
            if len(history) % 20 == 0:
                print(f"Iter {len(history)}: loss={l:.4f}")

        res = minimize(lambda p: self.loss(p, X, y), init,
                      method='COBYLA', options={'maxiter': maxiter}, callback=callback)
        return {'params': res.x, 'loss': res.fun, 'history': history}

    def predict(self, X: np.ndarray, params: np.ndarray) -> np.ndarray:
        return np.array([1 if self.forward(x, params) > 0.5 else 0 for x in X])

def generate_data(n_samples: int = 100):
    np.random.seed(42)
    X0 = np.random.randn(n_samples // 2, 2) * 0.5
    X1 = np.random.randn(n_samples // 2, 2) * 0.5 + np.array([1, 1])
    X = np.vstack([X0, X1])
    y = np.array([0] * (n_samples // 2) + [1] * (n_samples // 2))
    X = (X - X.min(axis=0)) / (X.max(axis=0) - X.min(axis=0) + 1e-10)
    idx = np.random.permutation(n_samples)
    return X[idx], y[idx]

X, y = generate_data(100)
X_train, X_test = X[:80], X[80:]
y_train, y_test = y[:80], y[80:]

vqc = VQClassifier(n_qubits=2, n_layers=2)
result = vqc.train(X_train, y_train, maxiter=100)

train_acc = np.mean(vqc.predict(X_train, result['params']) == y_train)
test_acc = np.mean(vqc.predict(X_test, result['params']) == y_test)

print(f"\nVQC Train accuracy: {train_acc:.3f}")
print(f"VQC Test accuracy: {test_acc:.3f}")

import numpy as np
from typing import Dict

class EncodingComparison:
    def __init__(self, n_qubits: int):
        self.n_qubits = n_qubits
        self.dim = 2 ** n_qubits

    def _apply_ry(self, state, q, theta):
        new = np.zeros_like(state)
        c, s = np.cos(theta/2), np.sin(theta/2)
        for i in range(len(state)):
            b = (i >> q) & 1
            i0, i1 = i & ~(1<<q), i | (1<<q)
            if b == 0:
                new[i0] += c * state[i]
                new[i1] += s * state[i]
            else:
                new[i0] -= s * state[i]
                new[i1] += c * state[i]
        return new

    def _apply_h(self, state, q):
        new = np.zeros_like(state)
        for i in range(len(state)):
            b = (i >> q) & 1
            i0, i1 = i & ~(1<<q), i | (1<<q)
            if b == 0:
                new[i0] += state[i]/np.sqrt(2)
                new[i1] += state[i]/np.sqrt(2)
            else:
                new[i0] += state[i]/np.sqrt(2)
                new[i1] -= state[i]/np.sqrt(2)
        return new

    def _apply_rz(self, state, q, theta):
        new = state.copy()
        for i in range(len(state)):
            b = (i >> q) & 1
            new[i] *= np.exp(1j*theta/2) if b else np.exp(-1j*theta/2)
        return new

    def _apply_rzz(self, state, q1, q2, theta):
        new = state.copy()
        for i in range(len(state)):
            parity = ((i>>q1)&1 + (i>>q2)&1)%2
            new[i] *= np.exp(1j*theta/2) if parity else np.exp(-1j*theta/2)
        return new

    def angle_encoding(self, x: np.ndarray) -> np.ndarray:
        state = np.zeros(self.dim, dtype=complex)
        state[0] = 1
        for q in range(min(self.n_qubits, len(x))):
            state = self._apply_ry(state, q, np.pi * x[q])
        return state

    def amplitude_encoding(self, x: np.ndarray) -> np.ndarray:
        padded = np.zeros(self.dim)
        padded[:min(len(x), self.dim)] = x[:min(len(x), self.dim)]
        norm = np.linalg.norm(padded)
        return (padded / norm if norm > 0 else padded).astype(complex)

    def iqp_encoding(self, x: np.ndarray, reps: int = 2) -> np.ndarray:
        state = np.zeros(self.dim, dtype=complex)
        state[0] = 1
        for q in range(self.n_qubits):
            state = self._apply_h(state, q)
        for _ in range(reps):
            for q in range(self.n_qubits):
                state = self._apply_rz(state, q, x[q%len(x)] * np.pi)
            for q in range(self.n_qubits - 1):
                state = self._apply_rzz(state, q, q+1, x[q%len(x)]*x[(q+1)%len(x)]*np.pi)
        return state

    def entanglement_entropy(self, state: np.ndarray) -> float:
        rho = np.zeros((2, 2), dtype=complex)
        half = self.dim // 2
        for i in range(half):
            rho[0, 0] += np.abs(state[i])**2
            rho[1, 1] += np.abs(state[i + half])**2
        eig = np.linalg.eigvalsh(rho)
        eig = eig[eig > 1e-10]
        return -np.sum(eig * np.log2(eig + 1e-10))

    def state_fidelity(self, s1: np.ndarray, s2: np.ndarray) -> float:
        return np.abs(np.vdot(s1, s2))**2

    def encoding_sensitivity(self, encoding_func, x: np.ndarray, epsilon: float = 0.01) -> float:
        state = encoding_func(x)
        total_change = 0
        for i in range(len(x)):
            x_pert = x.copy()
            x_pert[i] += epsilon
            state_pert = encoding_func(x_pert)
            total_change += 1 - self.state_fidelity(state, state_pert)
        return total_change / len(x)

    def compare_all(self, X: np.ndarray) -> Dict:
        encodings = {
            'angle': self.angle_encoding,
            'amplitude': self.amplitude_encoding,
            'iqp': self.iqp_encoding
        }
        results = {}
        for name, func in encodings.items():
            entropies, sensitivities = [], []
            states = []
            for x in X:
                s = func(x)
                states.append(s)
                entropies.append(self.entanglement_entropy(s))
                sensitivities.append(self.encoding_sensitivity(func, x))

            diversity = np.mean([1 - self.state_fidelity(states[i], states[j]) 
                                for i in range(len(states)) for j in range(i+1, len(states))])
            results[name] = {
                'mean_entanglement': np.mean(entropies),
                'mean_sensitivity': np.mean(sensitivities),
                'state_diversity': diversity
            }
        return results

np.random.seed(42)
X_test = np.random.rand(20, 4)
comp = EncodingComparison(n_qubits=4)
results = comp.compare_all(X_test)

print("Encoding Comparison Results")
print("="*50)
for enc, metrics in results.items():
    print(f"\n{enc.upper()}:")
    print(f"  Mean entanglement: {metrics['mean_entanglement']:.4f}")
    print(f"  Mean sensitivity: {metrics['mean_sensitivity']:.4f}")
    print(f"  State diversity: {metrics['state_diversity']:.4f}")

import numpy as np
from typing import Callable
from scipy.stats import beta

class ExpressibilityAnalyzer:
    def __init__(self, n_qubits: int):
        self.n_qubits = n_qubits
        self.dim = 2 ** n_qubits

    def sample_haar_random_state(self) -> np.ndarray:
        real = np.random.randn(self.dim)
        imag = np.random.randn(self.dim)
        state = real + 1j * imag
        return state / np.linalg.norm(state)

    def haar_fidelity_distribution(self, n_samples: int = 1000) -> np.ndarray:
        fids = []
        for _ in range(n_samples):
            s1 = self.sample_haar_random_state()
            s2 = self.sample_haar_random_state()
            fids.append(np.abs(np.vdot(s1, s2))**2)
        return np.array(fids)

    def circuit_fidelity_distribution(self, circuit_func: Callable,
                                      n_params: int, n_samples: int = 1000) -> np.ndarray:
        fids = []
        for _ in range(n_samples):
            p1 = np.random.randn(n_params) * np.pi
            p2 = np.random.randn(n_params) * np.pi
            s1 = circuit_func(p1)
            s2 = circuit_func(p2)
            fids.append(np.abs(np.vdot(s1, s2))**2)
        return np.array(fids)

    def kl_divergence(self, p: np.ndarray, q: np.ndarray, n_bins: int = 75) -> float:
        hist_p, bins = np.histogram(p, bins=n_bins, range=(0, 1), density=True)
        hist_q, _ = np.histogram(q, bins=bins, density=True)
        hist_p = hist_p / hist_p.sum() + 1e-10
        hist_q = hist_q / hist_q.sum() + 1e-10
        return np.sum(hist_p * np.log(hist_p / hist_q))

    def expressibility(self, circuit_func: Callable, n_params: int,
                       n_samples: int = 1000) -> float:
        circuit_fids = self.circuit_fidelity_distribution(circuit_func, n_params, n_samples)
        haar_fids = self.haar_fidelity_distribution(n_samples)
        return self.kl_divergence(circuit_fids, haar_fids)

    def analyze_depth_scaling(self, circuit_generator: Callable,
                              max_layers: int = 5) -> dict:
        results = {'layers': [], 'expressibility': []}
        for L in range(1, max_layers + 1):
            circuit = circuit_generator(L)
            expr = self.expressibility(circuit, circuit.n_params, 500)
            results['layers'].append(L)
            results['expressibility'].append(expr)
        return results

class TestCircuit:
    def __init__(self, n_qubits: int, n_layers: int):
        self.n_qubits = n_qubits
        self.n_layers = n_layers
        self.n_params = n_qubits * n_layers * 2
        self.dim = 2 ** n_qubits

    def __call__(self, params: np.ndarray) -> np.ndarray:
        state = np.zeros(self.dim, dtype=complex)
        state[0] = 1
        idx = 0
        for _ in range(self.n_layers):
            for q in range(self.n_qubits):
                theta = params[idx]
                c, s = np.cos(theta/2), np.sin(theta/2)
                new = np.zeros_like(state)
                for i in range(self.dim):
                    b = (i >> q) & 1
                    i0, i1 = i & ~(1<<q), i | (1<<q)
                    if b == 0:
                        new[i0] += c*state[i]
                        new[i1] += s*state[i]
                    else:
                        new[i0] -= s*state[i]
                        new[i1] += c*state[i]
                state = new
                idx += 1
            for q in range(self.n_qubits):
                theta = params[idx]
                for i in range(self.dim):
                    b = (i >> q) & 1
                    state[i] *= np.exp(1j*theta/2) if b else np.exp(-1j*theta/2)
                idx += 1
            for q in range(self.n_qubits - 1):
                new = np.zeros_like(state)
                for i in range(self.dim):
                    cb = (i >> q) & 1
                    if cb:
                        new[i ^ (1 << (q+1))] = state[i]
                    else:
                        new[i] = state[i]
                state = new
        return state

analyzer = ExpressibilityAnalyzer(n_qubits=3)
print("Expressibility Analysis")
print("="*50)
for n_layers in [1, 2, 3, 4, 5]:
    circuit = TestCircuit(n_qubits=3, n_layers=n_layers)
    expr = analyzer.expressibility(circuit, circuit.n_params, n_samples=500)
    print(f"Layers={n_layers}: Expressibility (KL) = {expr:.4f}")
